def verify(answer):
    from sympy import symbols, Poly, simplify
    x = symbols('x')
    poly = Poly(x**4 + 2*x**3 - 7*x**2 - 8*x + 12, x)
    # Parse answer as a list of numbers
    try:
        if isinstance(answer, str):
            roots = [s.strip() for s in answer.split(',')]
        elif isinstance(answer, (list, tuple)):
            roots = list(answer)
        else:
            return False
        # Convert to sympy numbers
        parsed_roots = []
        for r in roots:
            try:
                parsed_roots.append(simplify(r))
            except Exception:
                return False
        # Check that all roots are roots of the polynomial
        for r in parsed_roots:
            val = poly.eval(r)
            # Allow for small numerical errors
            if abs(complex(val)) > 1e-8:
                return False
        # Check that all roots of the polynomial are included (multiplicities)
        poly_roots = poly.all_roots(multiple=True)
        # Compare multisets
        from collections import Counter
        # Use complex numbers for comparison, rounded to 8 decimals
        def to_cmp(z):
            z = complex(z)
            return (round(z.real,8), round(z.imag,8))
        parsed_counter = Counter([to_cmp(r) for r in parsed_roots])
        poly_counter = Counter([to_cmp(r) for r in poly_roots])
        return parsed_counter == poly_counter
    except Exception:
        return False

