def verify(answer):
    from sympy import Interval, Symbol, solveset, S
    import re

    x = Symbol('x', real=True)
    expr = ((x + 7)*(x - 2))/(x - 1)
    # Find where the expression is less than 0
    sol = solveset(expr < 0, x, domain=S.Reals)
    # Convert sympy IntervalUnion to a string in interval notation
    def interval_to_str(interval):
        if interval.is_EmptySet:
            return ""
        if interval.is_Interval:
            left = "(" if not interval.left_open else "("
            right = ")" if not interval.right_open else ")"
            a = "-oo" if interval.start == -S.Infinity else str(interval.start)
            b = "oo" if interval.end == S.Infinity else str(interval.end)
            return f"{left}{a}, {b}{right}"
        elif interval.is_Union:
            return " U ".join(interval_to_str(arg) for arg in interval.args)
        else:
            return str(interval)
    correct = interval_to_str(sol).replace(" ", "")
    # Acceptable answer formats: (a, b), (a, b)U(c, d), etc.
    # Remove all whitespace and standardize -oo/oo
    def standardize(s):
        s = s.replace("−", "-").replace("∞", "oo").replace("inf", "oo")
        s = s.replace(" ", "")
        s = re.sub(r'(?i)U', 'U', s)
        return s
    try:
        user = standardize(str(answer))
        return user == correct
    except Exception:
        return False

