    count = 0
    # Let the sides be (a, a, b) or (a, b, b), with a, b positive integers
    # Perimeter: 2a + b = 20 or a + 2b = 20
    # All sides must satisfy triangle inequality: sum of any two > third

    # Case 1: (a, a, b)
    for a in range(1, 20):
        b = 20 - 2 * a
        if b <= 0:
            continue
        # Triangle inequalities:
        # a + a > b => 2a > b
        # a + b > a => b > 0 (already true)
        # a + b > a => b > 0 (already true)
        if 2 * a > b and b > 0:
            # (a, a, b) and (a, b, a) and (b, a, a) are the same triangle
            count += 1

    # Case 2: (a, b, b)
    for b in range(1, 20):
        a = 20 - 2 * b
        if a <= 0:
            continue
        # Triangle inequalities:
        # b + b > a => 2b > a
        # b + a > b => a > 0 (already true)
        # b + a > b => a > 0 (already true)
        if 2 * b > a and a > 0:
            # (a, b, b) and (b, a, b) and (b, b, a) are the same triangle
            # To avoid double-counting, only count if a != b
            if a != b:
                count += 1
            else:
                # If a == b, then (a, a, a): equilateral triangle
                # Only count once
                count += 1

    # Remove duplicates: (a, a, b) and (b, b, a) with a != b are the same triangle
    # So, we need to count unique triangles up to side permutation
    triangles = set()
    # Re-enumerate and store sorted tuples
    for a in range(1, 20):
        b = 20 - 2 * a
        if b <= 0:
            continue
        if 2 * a > b and b > 0:
            sides = tuple(sorted([a, a, b]))
            triangles.add(sides)
    for b in range(1, 20):
        a = 20 - 2 * b
        if a <= 0:
            continue
        if 2 * b > a and a > 0:
            sides = tuple(sorted([a, b, b]))
            triangles.add(sides)
    try:
        return int(str(answer).strip()) == len(triangles)
    except Exception:
